# Inspect Generated Code
#
# This script shows exactly what code is generated by GridCodec
# to help identify optimization opportunities.

defmodule InspectCodec do
  @moduledoc """
  A codec where we can examine the generated code.
  """
  use GridCodec

  defcodec do
    field(:id, :u64)
    field(:count, :u32)
    field(:flag, :bool)
  end
end

IO.puts("=== Generated Encode Function ===\n")

# Get the abstract code from the beam chunk
# We can use Module.get_attribute at compile time to see the generated code
# But at runtime, we need to inspect the function

# Show what the encode function looks like by timing different parts
data = %{id: 12345, count: 100, flag: true}

# Test 1: Full encode
IO.puts("Testing full encode:")
{time1, binary} = :timer.tc(fn ->
  for _ <- 1..100_000, do: InspectCodec.encode(data)
end)
IO.puts("  InspectCodec.encode/1: #{time1/1000}ms for 100k iterations")
IO.puts("  Binary size: #{byte_size(List.last(binary))} bytes")

# Test 2: Just Map.get calls
IO.puts("\nTesting Map.get overhead:")
{time2, _} = :timer.tc(fn ->
  for _ <- 1..100_000 do
    Map.get(data, :id, 18446744073709551615)
    Map.get(data, :count, 4294967295)
    Map.get(data, :flag, 255)
  end
end)
IO.puts("  3x Map.get: #{time2/1000}ms for 100k iterations")

# Test 3: Binary construction only
IO.puts("\nTesting binary construction:")
id = 12345
count = 100
flag_byte = 1
{time3, _} = :timer.tc(fn ->
  for _ <- 1..100_000 do
    <<id::little-64, count::little-32, flag_byte::8>>
  end
end)
IO.puts("  Raw binary: #{time3/1000}ms for 100k iterations")

# Test 4: Combined
IO.puts("\nTesting combined Map.get + binary:")
{time4, _} = :timer.tc(fn ->
  for _ <- 1..100_000 do
    id = Map.get(data, :id, 18446744073709551615)
    count = Map.get(data, :count, 4294967295)
    flag = Map.get(data, :flag, 255)
    flag_byte = case flag do
      true -> 1
      false -> 0
      _ -> 255
    end
    <<id::little-64, count::little-32, flag_byte::8>>
  end
end)
IO.puts("  Map.get + binary: #{time4/1000}ms for 100k iterations")

IO.puts("\n=== Analysis ===")
IO.puts("GridCodec encode overhead: #{Float.round((time1 - time4) / time4 * 100, 1)}% vs manual")
IO.puts("Map.get is #{Float.round(time2 / time3 * 100, 1)}% of binary construction time")

# Now let's look at what the generated case statement does for bool
IO.puts("\n=== Bool Encoding Analysis ===")

# The current bool encode does:
# case Map.get(data, :flag, 255) do
#   true -> 1
#   false -> 0
#   _ -> 255
# end :: 8

# But since default is 255, Map.get(%{}, :flag, 255) returns 255
# Then case 255 of true -> 1; false -> 0; _ -> 255 end returns 255
# This works but has unnecessary case matching

# Test with simplified approach
IO.puts("\nComparing bool encoding strategies:")

{t_case, _} = :timer.tc(fn ->
  for _ <- 1..100_000 do
    v = Map.get(data, :flag, 255)
    case v do
      true -> 1
      false -> 0
      _ -> 255
    end
  end
end)
IO.puts("  case statement: #{t_case/1000}ms")

{t_cond, _} = :timer.tc(fn ->
  for _ <- 1..100_000 do
    v = Map.get(data, :flag)
    cond do
      v == true -> 1
      v == false -> 0
      true -> 255
    end
  end
end)
IO.puts("  cond statement: #{t_cond/1000}ms")

# Direct approach
{t_direct, _} = :timer.tc(fn ->
  for _ <- 1..100_000 do
    v = Map.get(data, :flag)
    if v == true, do: 1, else: if(v == false, do: 0, else: 255)
  end
end)
IO.puts("  nested if: #{t_direct/1000}ms")

# Pattern match version
{t_pattern, _} = :timer.tc(fn ->
  for _ <- 1..100_000 do
    case data do
      %{flag: true} -> 1
      %{flag: false} -> 0
      _ -> 255
    end
  end
end)
IO.puts("  pattern match on map: #{t_pattern/1000}ms")

IO.puts("\n=== Decode Analysis ===")

binary = <<12345::little-64, 100::little-32, 1::8>>

{decode_time, _} = :timer.tc(fn ->
  for _ <- 1..100_000, do: InspectCodec.decode(binary)
end)
IO.puts("InspectCodec.decode/1: #{decode_time/1000}ms for 100k iterations")

# Manual decode
{manual_decode_time, _} = :timer.tc(fn ->
  for _ <- 1..100_000 do
    <<id::little-64, count::little-32, flag_byte::8>> = binary
    flag = case flag_byte do
      0 -> false
      255 -> nil
      _ -> true
    end
    {:ok, %{id: id, count: count, flag: flag}}
  end
end)
IO.puts("Manual decode: #{manual_decode_time/1000}ms for 100k iterations")

IO.puts("\nDecode overhead: #{Float.round((decode_time - manual_decode_time) / manual_decode_time * 100, 1)}%")

# Check what overhead comes from the groups/var sections
IO.puts("\n=== Groups/Var Section Overhead ===")

{decode_no_groups_time, _} = :timer.tc(fn ->
  for _ <- 1..100_000 do
    <<id::little-64, count::little-32, flag_byte::8, rest::binary>> = binary
    flag = case flag_byte do
      0 -> false
      255 -> nil
      _ -> true
    end
    # Simulating empty groups_map and var_map merge
    fixed_map = %{id: id, count: count, flag: flag}
    groups_map = %{}
    var_map = %{}
    result = fixed_map |> Map.merge(groups_map) |> Map.merge(var_map)
    {:ok, result}
  end
end)
IO.puts("Decode with Map.merge overhead: #{decode_no_groups_time/1000}ms")
